import { HeaderEntries } from "@/lib/types";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuShortcut,
  DropdownMenuTrigger,
} from "./ui/dropdown-menu";
import { Button } from "./ui/button";
import { IconMenu2 } from "@tabler/icons-react";
import { capitalize } from "@/lib/utils";
import Link from "next/link";

export default function Nav({ entries }: { entries: HeaderEntries }) {
  return (
    <div id="nav" role="nav" className="contents">
      <div id="icon-nav" role="icon-nav" className="md:hidden">
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button variant="ghost" size="icon">
              <IconMenu2 />
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent>
            {entries.map((entry) => (
              <DropdownMenuItem key={entry.page}>
                <entry.Icon />
                <Link href={`/${entry.page}`}>{capitalize(entry.page)}</Link>
                <DropdownMenuShortcut>{`⇧⌘${capitalize(entry.page.charAt(0))}`}</DropdownMenuShortcut>
              </DropdownMenuItem>
            ))}
          </DropdownMenuContent>
        </DropdownMenu>
      </div>
      <div id="full-nav" role="full-nav" className="hidden md:block">
        <ul className="flex justify-end items-center gap-2 h-full text-lg">
          {entries.map((entry) => (
            <li key={entry.page} className="flex gap-2">
              <entry.Icon />
              <Link href={`/${entry.page}`}>{capitalize(entry.page)}</Link>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
}
